    "template": "{{#if (occurrences imageUrl.src '/uploaded_images/')}}\n    {{assignVar 'filename' (last (split imageUrl.src '/uploaded_images/'))}}\n{{/if}}\n<style>\n    #sd-image-{{_.id}} {\n        display: flex;\n        align-items: center;\n        background: url('{{{imageUrl.src}}}') no-repeat;\n        opacity: calc({{imageOpacity}} / 100);\n\n        {{#if imageUrlType '!==' 'none'}}\n            cursor: pointer;\n        {{/if}}\n\n        {{#if imageFit '===' 'fill'}}\n            background-size: cover;\n            {{#if imageParallax '===' 'on'}}\n                background-attachment: fixed;\n            {{/if}}\n        {{else}}\n            background-size: contain;\n        {{/if}}\n\n        {{#if imageDimensionType '===' 'auto'}}\n            height: auto;\n        {{else}}\n            height: {{imageHeight.value}}{{imageHeight.type}};\n        {{/if}}\n\n        background-position:\n            {{#if imageAlignment.horizontal '===' 'center'}}\n                center\n            {{else if imageAlignment.horizontal '===' 'left'}}\n                left\n            {{else if imageAlignment.horizontal '===' 'right'}}\n                right\n            {{/if}}\n            {{#if imageAlignment.vertical '===' 'middle'}}\n                center\n            {{else if imageAlignment.vertical '===' 'top'}}\n                top\n            {{else if imageAlignment.vertical '===' 'bottom'}}\n                bottom\n            {{/if}};\n\n        {{#if borderStyle '!==' 'none'}}\n            border: {{borderThickness}}px {{borderStyle}} {{borderColor}};\n        {{/if}}\n\n        padding-top: {{containerPadding.top.value}}{{containerPadding.top.type}};\n        padding-right: {{containerPadding.right.value}}{{containerPadding.right.type}};\n        padding-bottom: {{containerPadding.bottom.value}}{{containerPadding.bottom.type}};\n        padding-left: {{containerPadding.left.value}}{{containerPadding.left.type}};\n\n        margin-top: {{containerMargin.top.value}}{{containerMargin.top.type}};\n        margin-right: {{containerMargin.right.value}}{{containerMargin.right.type}};\n        margin-bottom: {{containerMargin.bottom.value}}{{containerMargin.bottom.type}};\n        margin-left: {{containerMargin.left.value}}{{containerMargin.left.type}};\n    }\n\n    #sd-image-{{_.id}} * {\n        margin: 0px;\n    }\n\n    #sd-image-{{_.id}} img {\n        width: auto;\n        opacity: 0;\n\n        {{#if imageDimensionType '===' 'auto'}}\n            height: auto;\n        {{else}}\n            height: 100%;\n        {{/if}}\n    }\n\n    @media only screen and (max-width: 700px) {\n        #sd-image-{{_.id}} { }\n    }\n</style>\n\n<div>\n    {{#if imageUrlType '!==' 'none'}}\n        <div onclick=\"handleClick('{{imageLink}}')\" role=\"button\">\n    {{/if}}\n    <div id=\"sd-image-{{_.id}}\" data-edit-mode=\"{{_.pageBuilderData.previewState.editMode}}\">\n        <img src=\"{{imageUrl.src}}\" {{#if (getVar 'filename')}}srcset=\"{{getImageManagerImageSrcset (getVar 'filename')}}\"{{/if}} alt=\"{{altText}}\">\n    </div>\n    {{#if imageUrlType '!==' 'none'}}</div>{{/if}}\n</div>\n\n<script type=\"text/javascript\">\n    (function () {\n        var editMode = false;\n        var selector = \"sd-image-{{_.id}}\";\n        var element = document.getElementById(selector);\n        if (!element) { return; }\n\n        function initializeEditMode() {\n            if (window.BigCommerce && window.BigCommerce.inlineEditor) {\n                editMode = true;\n            }\n        }\n\n        function setEditMode(data) {\n            editMode = data.editMode;\n            element.dataset.editMode = editMode;\n\n            initializeEditMode();\n        }\n\n        window.addEventListener('message', function (event) {\n            try {\n                var data = JSON.parse(event.data);\n            } catch (error) {\n                return;\n            }\n\n            [{\n                action: 'sdk-loaded',\n                initiator: 'PAGE_BUILDER',\n                callback: initializeEditMode\n            },{\n                action: 'toggle-edit-mode',\n                initiator: 'PAGE_BUILDER',\n                callback: setEditMode\n            }].forEach(function (handler) {\n                if (data.action === handler.action && data.initiator === handler.initiator) {\n                    try { handler.callback(data); } catch (error) {}\n                }\n            })\n        });\n\n        initializeEditMode();\n    })();\n\n    function handleClick(imageLink) {\n        var trimmedLink = imageLink.trim();\n        if (!trimmedLink) { return; }\n\n        var selector = \"sd-image-{{_.id}}\";\n        var element = document.getElementById(selector);\n        var editMode = element.dataset.editMode || false;\n\n        if (editMode !== 'true') {\n            var urlParts = trimmedLink.split('/');\n            var protocol = urlParts[0];\n            var isUnformatted = protocol !== ' &&\n                protocol.indexOf('http') === -1 &&\n                trimmedLink.indexOf('.') !== -1;\n\n            // check if absolute link and is not properly formatted\n            if (isUnformatted) {\n                urlParts.unshift('/');\n            }\n\n            var newUrl = urlParts.join('/');\n            window.open(newUrl, '_top');\n        }\n    }\n</script>\n",
    "client_rerender": false
}

